CustomField.formula:
IF( RecordType.Name = 'Apartments',
/* APARTMENT - Full Calculation */ (Rate_per_sqft__c * Super_Built_UpArea__c )+ (Unit__r.Floor_Rise_Charge__c * Super_Built_UpArea__c) + (Unit__r.East_Facing_Charges__c * Super_Built_UpArea__c) + (Unit__r.Corner_Charges__c * Super_Built_UpArea__c) + (Unit__r.Road_View_Charges__c * Super_Built_UpArea__c )+ (Unit__r.ORR_View_Charges__c * Super_Built_UpArea__c) + (Unit__r.Garden_View_Charges__c * Super_Built_UpArea__c) + (Unit__r.Clubhouse_Charges__c) + (Unit__r.Water_Electricity_Charges__c) + (Unit__r.Car_Parking__c),
/* PLOT - Simple Calculation */ Base_Value__c + Total_Infrastructure_Charges__c )
